PLAYLISTS = [{"slug": "most-popular-ted-talks-of-2025", "title": "Most popular TED Talks of 2025", "description": "Here are the talks everyone couldn’t stop watching in 2025. From how to spot deepfakes and read minds to breakthroughs in robotics and longer-lasting produce, these ideas captured attention — and sparked conversation worldwide.", "topic": "technology|culture|science|personal growth|social change"}, {"slug": "most-popular-ted-conversations-of-2025", "title": "Most popular TED conversations of 2025", "description": "TED conversations in 2025 brought bold and transformative questions to the forefront. Dive deeper into the ideas shaping our world and hear insights on how to move forward with purpose.", "topic": "communication|culture|society|identity|democracy"}, {"slug": "most-popular-ted-ed-animations-of-2025", "title": "Most popular TED-Ed animations of 2025", "description": "Explore the most popular TED-Ed animations of 2025, covering the brain and body, myths and mysteries, and more. From the science of cholesterol and social isolation to the history of dragon legends, the health benefits of walking and more, these lessons are perfect for curious minds.", "topic": "ted-ed|animation|education|science"}, {"slug": "the-best-ted-podcasts-of-2025", "title": "The best TED Podcasts of 2025", "description": "These TED Podcasts dive into the ideas shaping 2025, from episodes on life hacks and groundbreaking science to interviews with experts and cultural icons. Hear how to beat imposter syndrome, why seaweed is great at cutting methane and what everyday habits can make you a better human.", "topic": "storytelling|culture|psychology|communication"}, {"slug": "ted-talks-for-when-you-re-planning-your-wedding", "title": "TED Talks for when you’re planning your wedding", "description": "The venue is booked, the flowers are chosen, the dress is perfect. These talks get into the real stuff — how to communicate honestly, love better and build something that actually lasts.", "topic": "relationships|love|communication|marriage|family"}, {"slug": "new-tech-new-ethics", "title": "New tech, new ethics", "description": "With technical advancement comes great ethical responsibility. In these talks, life-altering feats of science make us ask: How could we mess this up?", "topic": "technology|ai|ethics|data|privacy|future"}, {"slug": "the-10-day-resilience-challenge", "title": "The 10-day resilience challenge", "description": "A 10-day reset for your mindset: watch one talk a day to explore different ways of building resilience — from handling fear and rejection to practicing courage, grit and risk-taking.", "topic": "personal growth|psychology|emotions|happiness|mental health"}, {"slug": "the-pursuit-of-curiosity", "title": "The pursuit of curiosity", "description": "Not all who wander are lost — some are just following their curiosity. These TED Talks are for the question-askers, the pattern-noticers, the people who go down rabbit holes and don't regret it.", "topic": "creativity|science|education|innovation"}, {"slug": "talks-for-when-you-feel-totally-burned-out", "title": "Talks for when you feel totally burned out", "description": "Burnout isn't just a bad day — it's what happens when stress piles up over time. If you're running on empty and need a reset, this collection of talks is a good place to start.", "topic": "work|mental health|happiness|psychology|emotions"}, {"slug": "ted-talks-every-therapist-should-watch", "title": "TED Talks every therapist should watch", "description": "Whether you’re a therapist guiding others or a client navigating your own mental health, these talks offer science-backed insights on anxiety, resilience and relationships. Dive in to learn how your brain shapes your emotions — and unlock behaviors to help you better understand yourself and those around you.", "topic": "psychology|mental health|emotions|identity|health"}, {"slug": "talks-to-help-you-forget-that-you-re-doing-chores", "title": "Talks to help you forget that you're doing chores", "description": "Whether you are washing dishes, dusting the shelves or cleaning the car, these talks will help the next hour fly by. No need to watch — just listen.", "topic": "humor|storytelling|culture|entertainment"}, {"slug": "ted-talks-for-people-who-hate-public-speaking", "title": "TED Talks for people who hate public speaking", "description": "Dreading the spotlight? You’re not alone. Whether you freeze at the thought of presenting or just want to communicate with more confidence, these speakers explore why stage fright happens — and give practical tips on how to overcome it. ", "topic": "communication|public speaking|leadership|storytelling|performance"}, {"slug": "ted-talks-in-your-language", "title": "TED Talks in your language", "description": "What happens when ideas travel? Explore talks that matter to you — now available in your own language.", "topic": "language|culture|communication|identity"}, {"slug": "ted-talks-to-take-a-walk-with", "title": "TED Talks to take a walk with", "description": "Some of the world’s greatest minds swore by the benefits of taking a stroll. Explore science-backed reasons why walking can boost your brain, health and happiness.", "topic": "nature|personal growth|happiness|science"}, {"slug": "ted-talks-on-third-places", "title": "TED Talks on third places", "description": "Where do you go to feel like you belong? Beyond home and work, third places — from parks to plazas to online spaces — shape how we gather, connect and build community. These talks explore how thoughtful design and shared experiences can turn ordinary spaces into places that connect us.", "topic": "community|cities|society|culture|urbanism"}, {"slug": "ted-talks-on-dirt", "title": "TED Talks on dirt", "description": "Beneath your feet is a world teeming with life, intelligence and unexpected possibility. Dig into these talks to discover how soil, microbes, fungi and even death itself are quietly shaping the planet.", "topic": "nature|agriculture|sustainability|environment|science"}, {"slug": "the-brain-boosting-benefits-of-a-good-night-s-sleep", "title": "The brain-boosting benefits of a good night’s sleep", "description": "A good night’s sleep isn’t just about rest; it’s vital for your brain and body. From how many hours you really need to what causes insomnia, tune in to discover how it can quite literally reset your mind for a new day.", "topic": "brain|health|sleep|science|human body"}, {"slug": "talks-for-when-you-re-starting-a-new-job-feb-2017", "title": "Talks for when you're starting a new job", "description": "Being the new person is never easy. Let these talks help you in walking into your workplace with your shoulders back and head held high.", "topic": "work|business|leadership|communication|personal growth"}, {"slug": "ted-talks-about-the-moon", "title": "TED Talks about the Moon", "description": "Although these talks were not literally given on the Moon, their ideas are still out of this world.\n", "topic": "space|astronomy|science|exploration"}, {"slug": "10-talks-to-spark-your-democratic-spirit", "title": "10 talks to spark your democratic spirit", "description": "Dive into a collection of 10 inspiring TED talks curated to ignite your democratic spirit. From actionable strategies for political change to the power of citizen engagement, these talks will empower you to become an active participant in shaping our collective future. ", "topic": "democracy|politics|government|society|activism"}, {"slug": "synthetic-biology", "title": "Synthetic biology", "description": "From editing genes to designing life itself, synthetic biology is reshaping what’s possible in medicine, food and beyond. These talks explore the breakthroughs, ethical questions and real-world stakes of turning biology into technology.", "topic": "biology|science|technology|medicine|genetics"}, {"slug": "what-would-it-be-like-to-live-in-space", "title": "What would it be like to live in space?", "description": "Space is humanity's next destination — but what would it be like to actually live there?", "topic": "space|astronomy|science|future|technology"}, {"slug": "what-s-next-for-space-exploration", "title": "What’s next for space exploration?", "description": "Beyond our galaxy, there is much more to be discovered. From the Big Bang to humanity’s future on other planets, learn how we explore the universe with talks that are definitely out of this world.", "topic": "space|astronomy|science|innovation|exploration"}, {"slug": "let-s-talk-about-male-loneliness", "title": "Let’s talk about male loneliness", "description": "Loneliness among boys and men is a growing crisis. These talks take an honest, hopeful look at masculinity, mental health and belonging — offering fresh ideas for building stronger relationships and a deeper sense of purpose.", "topic": "relationships|emotions|mental health|identity|men"}, {"slug": "what-s-wrong-with-what-we-eat", "title": "What's wrong with what we eat?", "description": "It's easy to worry about food: Are we eating the wrong stuff? What about people who don't have enough to eat? These talks examine the problems — and some compelling solutions.", "topic": "food|health|sustainability|agriculture|culture"}, {"slug": "are-the-kids-alright", "title": "Are the kids alright?", "description": "Childhood is changing — and fast. From smartphones and social media to schools, parenting advice and more, these talks explore how technology, culture and policy are reshaping the way kids grow up. Dive into bold ideas on raising resilient, confident and curious young people in a world that’s rapidly changing.", "topic": "parenting|education|psychology|family|children"}, {"slug": "ted-ed-riddles", "title": "TED-Ed Riddles", "description": "What do giant cat armies, Leonardo da Vinci, birthday cake and the Trojan War all have in common? They’re part of this brain-busting riddle series from TED-Ed meant to test your might and mettle, your cunning and concentration, your puzzling prowess! Do you have what it takes to solve them?", "topic": "ted-ed|animation|education|math|logic"}, {"slug": "get-in-shape-for-real-this-time", "title": "Get in shape (for real this time) ", "description": "It is the New Year’s resolution that you make over and over again. Here, talks to help you actually stick to it — and do it in a kind, effective way.", "topic": "health|human body|personal growth|psychology|fitness"}]

